         public ActionResult Details(int? id)
         {
             if (id == null)
             {
                 return new StatusCodeResult((int)HttpStatusCode.BadRequest);
             }
             Student student = db.Students
                 .Include(s => s.Enrollments)
                     .ThenInclude(e => e.Course)
                 .Where(s => s.ID == id).Single();
             if (student == null)
             {
                 return NotFound();
             }
             return View(student);
         }

