using System;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelpers
    {
        public static SchoolContext CreateContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;
            return new SchoolContext(options);
        }

        public static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = DateTime.Parse("2013-09-01") }
            );
            context.SaveChanges();
        }

        public static Department SeedDepartmentWithInstructor(SchoolContext context)
        {
            var instructor = new Instructor
            {
                LastName = "Abercrombie",
                FirstMidName = "Kim",
                HireDate = DateTime.Parse("1995-03-11"),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var department = new Department
            {
                Name = "English",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = instructor.ID
            };
            context.Departments.Add(department);
            context.SaveChanges();

            return department;
        }

        public static Course SeedCourseWithDepartment(SchoolContext context)
        {
            var dept = SeedDepartmentWithInstructor(context);
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();
            return course;
        }
    }
}

using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain static queue to avoid cross-test contamination
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_CreatesNotificationWithCorrectFields()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("TestUser", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesProperMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Student 'John Doe'", notification.Message);
            Assert.Contains("created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_GeneratesMessageWithId()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Student (ID: 42)", notification.Message);
        }

        [Fact]
        public void ReceiveNotification_DequeuesInOrder()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("A", first!.EntityType);
            Assert.Equal("B", second!.EntityType);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNullWhenEmpty()
        {
            var result = _service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void SendNotification_QueueCapEnforcement()
        {
            for (int i = 0; i < 510; i++)
            {
                _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            // Queue should not exceed 500 items
            int count = 0;
            while (_service.ReceiveNotification() != null) count++;
            Assert.True(count <= 500);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "created")]
        [InlineData(EntityOperation.UPDATE, "updated")]
        [InlineData(EntityOperation.DELETE, "deleted")]
        public void GenerateMessage_ForEachOperation(EntityOperation operation, string expectedVerb)
        {
            _service.SendNotification("Course", "1", "Math", operation, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.Contains(expectedVerb, notification!.Message);
        }

        [Fact]
        public void GenerateMessage_WithDisplayName_ContainsName()
        {
            _service.SendNotification("Student", "1", "Jane Smith", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("Jane Smith", notification!.Message);
        }

        [Fact]
        public void GenerateMessage_WithoutDisplayName_ContainsId()
        {
            _service.SendNotification("Student", "99", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("ID: 99", notification!.Message);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var ex = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(ex);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var ex = Record.Exception(() => service.Dispose());
            Assert.Null(ex);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification!.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_DefaultUserIsSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification!.CreatedBy);
        }
    }
}

using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPageOfItems()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(5, result.Count);
            Assert.Equal(1, result[0]);
            Assert.Equal(5, result[4]);
        }

        [Fact]
        public void Create_SecondPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(5, result.Count);
            Assert.Equal(6, result[0]);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);
            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 5);
            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 4, 5);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);
            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void TotalPages_CalculatesCorrectly()
        {
            var source = Enumerable.Range(1, 23).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);
            Assert.Equal(5, result.TotalPages); // ceil(23/5) = 5
        }

        [Fact]
        public void TotalPages_ExactFit()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);
            Assert.Equal(4, result.TotalPages);
        }

        [Fact]
        public void Create_EmptySource()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_SinglePage()
        {
