using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain static queue to avoid cross-test contamination
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_CreatesNotificationWithCorrectFields()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("TestUser", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesProperMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Student 'John Doe'", notification.Message);
            Assert.Contains("created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_GeneratesMessageWithId()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Student (ID: 42)", notification.Message);
        }

        [Fact]
        public void ReceiveNotification_DequeuesInOrder()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("A", first!.EntityType);
            Assert.Equal("B", second!.EntityType);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNullWhenEmpty()
        {
            var result = _service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void SendNotification_QueueCapEnforcement()
        {
            for (int i = 0; i < 510; i++)
            {
                _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            // Queue should not exceed 500 items
            int count = 0;
            while (_service.ReceiveNotification() != null) count++;
            Assert.True(count <= 500);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "created")]
        [InlineData(EntityOperation.UPDATE, "updated")]
        [InlineData(EntityOperation.DELETE, "deleted")]
        public void GenerateMessage_ForEachOperation(EntityOperation operation, string expectedVerb)
        {
            _service.SendNotification("Course", "1", "Math", operation, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.Contains(expectedVerb, notification!.Message);
        }

        [Fact]
        public void GenerateMessage_WithDisplayName_ContainsName()
        {
            _service.SendNotification("Student", "1", "Jane Smith", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("Jane Smith", notification!.Message);
        }

        [Fact]
