            var dept = new Department { Name = "Test", Budget = 100, StartDate = DateTime.Today };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course { CourseID = 5000, Title = "Test", Credits = 3, DepartmentID = dept.DepartmentID };
            context.Courses.Add(course);
            var instructor = new Instructor
            {
                LastName = "T",
                FirstMidName = "I",
                HireDate = DateTime.Today,
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var ca = new CourseAssignment { CourseID = course.CourseID, InstructorID = instructor.ID };
            context.CourseAssignments.Add(ca);
            context.SaveChanges();

            var found = context.CourseAssignments.Find(course.CourseID, instructor.ID);
            Assert.NotNull(found);
        }

        [Fact]
        public void OfficeAssignment_OneToOneWithInstructor()
        {
