+        {
+            using var context = TestHelpers.CreateContext();
+
+            Assert.NotNull(context.Courses);
+            Assert.NotNull(context.Students);
+            Assert.NotNull(context.Instructors);
+            Assert.NotNull(context.Departments);
+            Assert.NotNull(context.Enrollments);
+            Assert.NotNull(context.CourseAssignments);
+            Assert.NotNull(context.OfficeAssignments);
+            Assert.NotNull(context.People);
+            Assert.NotNull(context.Notifications);
+        }
+
+        [Fact]
+        public void TPH_Inheritance_StudentAndInstructorSharePersonTable()
+        {
+            using var context = TestHelpers.CreateContext();
+            context.Students.Add(new Student { LastName = "S", FirstMidName = "T", EnrollmentDate = DateTime.Today });
+            context.Instructors.Add(new Instructor
+            {
+                LastName = "I",
+                FirstMidName = "T",
+                HireDate = DateTime.Today,
+                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
+            });
+            context.SaveChanges();
+
+            Assert.Equal(2, context.People.Count());
+            Assert.Single(context.Students);
+            Assert.Single(context.Instructors);
+        }
+
+        [Fact]
+        public void CourseAssignment_HasCompositeKey()
+        {
+            using var context = TestHelpers.CreateContext();
+            var dept = new Department { Name = "Test", Budget = 100, StartDate = DateTime.Today };
+            context.Departments.Add(dept);
+            context.SaveChanges();
+
+            var course = new Course { CourseID = 5000, Title = "Test", Credits = 3, DepartmentID = dept.DepartmentID };
+            context.Courses.Add(course);
+            var instructor = new Instructor
+            {
+                LastName = "T",
+                FirstMidName = "I",
+                HireDate = DateTime.Today,
+                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
+            };
+            context.Instructors.Add(instructor);
+            context.SaveChanges();
+
+            var ca = new CourseAssignment { CourseID = course.CourseID, InstructorID = instructor.ID };
+            context.CourseAssignments.Add(ca);
+            context.SaveChanges();
+
+            var found = context.CourseAssignments.Find(course.CourseID, instructor.ID);
+            Assert.NotNull(found);
+        }
+
+        [Fact]
+        public void OfficeAssignment_OneToOneWithInstructor()
+        {
+            using var context = TestHelpers.CreateContext();
+            var instructor = new Instructor
+            {
+                LastName = "Office",
+                FirstMidName = "Test",
+                HireDate = DateTime.Today,
+                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
+            };
+            context.Instructors.Add(instructor);
+            context.SaveChanges();
+
+            var office = new OfficeAssignment { InstructorID = instructor.ID, Location = "Room 101" };
+            context.OfficeAssignments.Add(office);
+            context.SaveChanges();
+
+            var loaded = context.OfficeAssignments.Include(o => o.Instructor).First();
+            Assert.Equal(instructor.ID, loaded.InstructorID);
+            Assert.Equal("Room 101", loaded.Location);
+        }
+    }
+}
